#include <stdio.h>
#include <stdlib.h>

int gcd_int(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int g = 0, mx = 0;
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            if (i == 0) g = x; else g = gcd_int(g, x);
            if (x > mx) mx = x;
        }
        printf("%d\n", mx / g);
    }
    return 0;
}

