import sys, math

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        g = 0
        mx = 0
        for i in range(N):
            x = int(next(it))
            if i == 0:
                g = x
            else:
                g = math.gcd(g, x)
            if x > mx:
                mx = x
        out.append(str(mx // g))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

